var MAX_FILE_SIZE_BYTES = 50 * 1024 * 1024;
async function uploadMedia(c) {
  const body = await c.req.parseBody();
  const file2 = body['file'];
  if (!file2) return throwError.badRequest('No file uploaded');
  if (file2.size <= 0) return throwError.badRequest('File is empty (size must be > 0)');
  if (file2.size > MAX_FILE_SIZE_BYTES)
    return throwError.badRequest(`File too large (max ${MAX_FILE_SIZE_BYTES / 1024 / 1024} MB)`, {
      fileSize: file2.size,
      maxSize: MAX_FILE_SIZE_BYTES,
    });
  if (file2.size > 2 * 1024 * 1024) {
    return throwError.badRequest('K\xEDch th\u01B0\u1EDBc \u1EA3nh kh\xF4ng \u0111\u01B0\u1EE3c v\u01B0\u1EE3t qu\xE1 2MB.');
  }
  const fileKey = createId();
  const fileType = file2.type;
  const fileSize = file2.size;
  await c.env.STORAGE.put(fileKey, file2.stream(), {
    httpMetadata: { contentType: fileType },
  });
  let result;
  try {
    result = await c.var.db
      .insert(media)
      .values({
        fileName: file2.name,
        fileType,
        fileSize,
        bucketKey: fileKey,
        createdBy: c.var.jwtPayload.id,
      })
      .returning()
      .get();
  } catch (err) {
    await c.env.STORAGE.delete(fileKey);
    throw err;
  }
  void writeAudit(c, {
    action: AuditAction.MEDIA_UPLOAD,
    entityType: 'media',
    entityId: result.id,
    newValue: {
      id: result.id,
      fileName: result.fileName,
      fileType: result.fileType,
      fileSize: result.fileSize,
      bucketKey: result.bucketKey,
    },
  });
  return result;
}
